// ===== Metadados =====
const fileName = $('Webhook').item.json.body.fileName || '';
const meses = {
  janeiro: '01', fevereiro: '02', 'março': '03', marco: '03', abril: '04',
  maio: '05', junho: '06', julho: '07', agosto: '08', setembro: '09',
  outubro: '10', novembro: '11', dezembro: '12'
};
const submittedAt = null;
function num(v) {
  if (v === undefined || v === null) return 0;
  const s = String(v).trim();
  if (s === '' || s === '-') return 0;
  const n = parseFloat(s.replace(/\./g, '').replace(',', '.'));
  return isNaN(n) ? 0 : n;
}
// ===== Junta todo o texto extraído do PDF =====
const allItems = $input.all();
let fullText = '';
for (const item of allItems) {
  const t = item.json.text;
  if (Array.isArray(t)) fullText += t.join('\n') + '\n';
  else if (typeof t === 'string') fullText += t + '\n';
}
// Data de referência: "Data: 06/2026" do PDF, senão nome do arquivo
let dataReferencia = null;
const dateMatch = fullText.match(/Data:\s*(\d{2})\/(\d{4})/i);
if (dateMatch) {
  dataReferencia = `${dateMatch[2]}-${dateMatch[1]}`;
} else {
  const fileMatch = fileName.match(/(\d{4})-([a-zçÇ]+)/i);
  if (fileMatch) {
    const mes = meses[fileMatch[2].toLowerCase()];
    if (mes) dataReferencia = `${fileMatch[1]}-${mes}`;
  }
}
// Normaliza espaçamento e junta o R$ separado por quebra de linha
let clean = fullText
  .replace(/\r/g, '')
  .replace(/\n\s*R\$\s*/g, ' R$ ')
  .replace(/R\$\s*\n\s*/g, ' R$ ')
  .replace(/\n/g, ' ')
  .replace(/\s+/g, ' ');
const rows = [];
// Delimitadores de seção (para saber onde cada tabela termina)
const todosTitulos = [
  /Posição\s*-\s*Ações/i, /Posição\s*-\s*BDR/i, /Posição\s*-\s*ETF/i,
  /Posição\s*-\s*FII/i, /Posição\s*-\s*Fundos/i, /Posição\s*-\s*RDB/i,
  /Posição\s*-\s*Tesouro/i, /Proventos\s+recebidos/i, /Reembolsos/i,
  /Negociação/i, /Resumo\s+dos\s+negócios/i
];
function fatia(inicioRegex, fimRegexList) {
  const ini = clean.search(inicioRegex);
  if (ini === -1) return '';
  let fim = clean.length;
  for (const fr of fimRegexList) {
    const idx = clean.slice(ini + 1).search(fr);
    if (idx !== -1 && (ini + 1 + idx) < fim) fim = ini + 1 + idx;
  }
  return clean.slice(ini, fim);
}
// =========================================================================
// RENDA VARIÁVEL: Ações, BDR, ETF, FII, Fundos
// =========================================================================
const secoesRV = [
  { titulo: /Posição\s*-\s*Ações/i, categoria: 'Ações' },
  { titulo: /Posição\s*-\s*BDR/i, categoria: 'BDR' },
  { titulo: /Posição\s*-\s*ETF/i, categoria: 'ETF' },
  { titulo: /Posição\s*-\s*FII/i, categoria: 'FII' },
  { titulo: /Posição\s*-\s*Fundos/i, categoria: 'Fundos de Investimentos' }
];
// "Internacional" = tipo dos ETFs globais; "ETF" = ETFs nacionais
const assetRegex = /([A-Z][A-Z0-9]{2,7})\s*-\s*(.+?)\s+(UNIT|ON|PN|Cotas|Direito|Fundo|Ações|BDR|Internacional|ETF)\s+([A-ZÀ-Ü][A-ZÀ-Ü\s.\/]+?(?:CTVM|CCTVM|CVMC|DTVM)[\w\s.\/]*?S\/?A)\s+(\d+)\s+R\$\s*([\d.,]+)\s+R\$\s*([\d.,]+)/gi;
for (const sec of secoesRV) {
  const fims = todosTitulos.filter(t => t.source !== sec.titulo.source);
  let texto = fatia(sec.titulo, fims);
  if (!texto) continue;
  // Remove título + cabeçalho da tabela (até "Valor Atualizado") de todas as páginas
  texto = texto.replace(/Posição\s*-\s*[^]*?Valor\s+Atualizado/gi, '');
  let m;
  assetRegex.lastIndex = 0;
  while ((m = assetRegex.exec(texto)) !== null) {
    rows.push({
      ticker: m[1].toUpperCase(),
      nome_ativo: m[2].trim(),
      tipo_ativo: m[3].trim(),
      instituicao: m[4].replace(/\s+/g, ' ').trim(),
      categoria: sec.categoria,
      quantidade: num(m[5]),
      preco_fechamento: num(m[6]),
      valor_atualizado: num(m[7]),
      tipo_registro: 'Posição Custódia',
      data_referencia: dataReferencia,
      submitted_at: submittedAt
    });
  }
}
// =========================================================================
// RDB
// =========================================================================
{
  let texto = fatia(/Posição\s*-\s*RDB/i,
    [/Posição\s*-\s*Tesouro/i, /Proventos/i, /Negociação/i]);
