        quantidade: num(vals[2]),
        preco_fechamento: num(vals[3]),   // valor aplicado
        valor_atualizado: num(vals[4]),   // valor atualizado
        tipo_registro: 'Posição Custódia',
        data_referencia: dataReferencia,
        submitted_at: submittedAt
      });
    }
  }
}
return rows.map(r => ({ json: r }));

