    data_referencia: dataReferencia,
    submitted_at: submittedAt
  });
}
for (const r of rowsFrom('Extrai Tesouro Direto')) {
  if (!r['Produto']) continue;
  const quantidade = num(r['Quantidade']);
  const valorAtualizado = num(r['Valor Atualizado']);
  rows.push({
    ticker: 'TESOURO',
    nome_ativo: r['Produto'],
    tipo_ativo: 'Título Público',
    instituicao: r['Instituição'] || null,
    categoria: 'Tesouro Direto',
    quantidade,
    preco_fechamento: quantidade > 0 ? valorAtualizado / quantidade : 0,
