}

function rowsFrom(nodeName) {
  try { return $(nodeName).all().map(i => i.json); } catch (e) { return []; }
}
const rows = [];
const posicaoNodes = {
  'Extrai Ações': 'Ações',
  'Extrai BDR': 'BDR',
  'Extrai ETF': 'ETF',
  'Extrai Fundos': 'Fundos de Investimentos'
};
for (const [nodeName, categoria] of Object.entries(posicaoNodes)) {
  for (const r of rowsFrom(nodeName)) {
    if (!r['Código de Negociação']) continue;
    const produto = String(r['Produto'] || '').trim();
    const partes = produto.split(' - ');
    const nome = partes.length > 1 ? partes.slice(1).join(' - ').trim() : produto;
    rows.push({
      ticker: String(r['Código de Negociação']).toUpperCase(),
      nome_ativo: nome,
      tipo_ativo: r['Tipo'] || null,
      instituicao: r['Instituição'] || null,
      categoria,
      quantidade: num(r['Quantidade']),
      preco_fechamento: num(r['Preço de Fechamento']),
      valor_atualizado: num(r['Valor Atualizado']),
      tipo_registro: 'Posição Custódia',
      data_referencia: dataReferencia,
      submitted_at: submittedAt
    });
  }
}
for (const r of rowsFrom('Extrai Renda Fixa')) {
  if (!r['Código']) continue;
  const produto = String(r['Produto'] || '').trim();
  rows.push({
    ticker: 'RDB',
    nome_ativo: produto,
    tipo_ativo: 'Renda Fixa',
    instituicao: r['Instituição'] || null,
    categoria: produto.toUpperCase().startsWith('RDB') ? 'RDB' : 'Renda Fixa',
    quantidade: num(r['Quantidade']),
    preco_fechamento: num(r['Preço Atualizado MTM']) || num(r['Preço Atualizado CURVA']),
    valor_atualizado: num(r['Valor Atualizado MTM']) || num(r['Valor Atualizado CURVA']),
    tipo_registro: 'Posição Custódia',
    data_referencia: dataReferencia,
    submitted_at: submittedAt
  });
}
for (const r of rowsFrom('Extrai Tesouro Direto')) {
  if (!r['Produto']) continue;
  const quantidade = num(r['Quantidade']);
  const valorAtualizado = num(r['Valor Atualizado']);
  rows.push({
    ticker: 'TESOURO',
    nome_ativo: r['Produto'],
    tipo_ativo: 'Título Público',
    instituicao: r['Instituição'] || null,
    categoria: 'Tesouro Direto',
    quantidade,
    preco_fechamento: quantidade > 0 ? valorAtualizado / quantidade : 0,
    valor_atualizado: valorAtualizado,
    tipo_registro: 'Posição Custódia',
    data_referencia: dataReferencia,
    submitted_at: submittedAt
  });
}
for (const r of rowsFrom('Extrai Negociações')) {
  if (!r['Código de Negociação']) continue;
  rows.push({
    ticker: String(r['Código de Negociação']).toUpperCase(),
    nome_ativo: 'Negociação de Ativo',
    tipo_ativo: 'Movimentação',
    instituicao: r['Instituição'] || null,
    categoria: 'Negociação',
    quantidade: num(r['Quantidade (Líquida)']),
    preco_fechamento: num(r['Preço Médio (Compra)']),
    valor_atualizado: num(r['Preço Médio (Venda)']),
    tipo_registro: 'Negociação',
    data_referencia: dataReferencia,
    submitted_at: submittedAt
  });
}
return rows.map(r => ({ json: r }));
